div.t-attf-style:
position: fixed;
bottom: {{ state.iconPos.bottom }}px;
right:  {{ state.iconPos.right  }}px;
background: #9EA700;
color: white;
border-radius: 50%;
width: 56px; height: 56px;
display: flex; align-items: center; justify-content: center;
font-size: 26px;
cursor: grab;
box-shadow: 0 4px 10px rgba(0,0,0,0.25);
z-index: 1050;
user-select: none;

position: fixed;
bottom: {{ state.chatPos.bottom }}px;
right:  {{ state.chatPos.right  }}px;
width: 520px;
height: 620px;
background: white;
border: 1px solid #ccc;
border-radius: 12px;
display: {{ state.aiChatOpen ? 'flex' : 'none' }};
flex-direction: column;
box-shadow: 0 8px 24px rgba(0,0,0,0.18);
z-index: 1050;
overflow: hidden;
user-select: none;

div.style:
background: #9EA700;
                    color: white;
                    padding: 10px 14px;
                    font-weight: 600;
                    font-size: 14px;
                    display: flex;
                    align-items: center;
                    gap: 8px;
                    flex-shrink: 0;
                    cursor: grab;
                    user-select: none;

div.t-attf-style:
max-width: 88%;
padding: 8px 12px;
border-radius: 12px;
font-size: 13px;
line-height: 1.5;
word-break: break-word;
{{ msg.from === 'user'
    ? 'align-self: flex-end; background: #9EA700; color: white; border-bottom-right-radius: 3px;'
    : msg.type === 'error'
        ? 'align-self: flex-start; background: #fdecea; color: #c62828; border: 1px solid #f5c6c6; border-bottom-left-radius: 3px;'
        : 'align-self: flex-start; background: #f2f2f2; color: #333; border-bottom-left-radius: 3px;'
}}

div.style:
align-self: flex-start; background: #f2f2f2; color: #666;
                            padding: 8px 14px; border-radius: 12px;
                            border-bottom-left-radius: 3px; font-size: 13px; font-style: italic;

button.t-attf-style:
background: {{ state.aiLoading ? '#bbb' : '#4b8bf5' }};
                              color: white; border: none; padding: 0 18px;
                              cursor: {{ state.aiLoading ? 'not-allowed' : 'pointer' }};
                              font-size: 13px; font-weight: 600;
                              transition: background 0.2s;
                              border-radius: 0 0 12px 0;
